1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Stockio Dashboard</title>
7	<script src="https://cdn.jsdelivr.net/npm/chart.js@4"></script>
8	<style>
9	  :root {
10	    --bg: #0f0f23;
11	    --card: #1a1a3e;
12	    --card-border: #2a2a5e;
13	    --text: #e0e0e0;
14	    --text-dim: #8888aa;
15	    --accent: #4fc3f7;
16	    --green: #4caf50;
17	    --red: #ef5350;
18	    --hold: #9e9e9e;
19	    --font: system-ui, -apple-system, sans-serif;
20	    --mono: 'JetBrains Mono', 'Fira Code', monospace;
21	  }
22	  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
23	  body { background: var(--bg); color: var(--text); font-family: var(--font); line-height: 1.5; padding: 0; }
24	  a { color: var(--accent); text-decoration: none; }
25	
26	  /* Header */
27	  .header {
28	    display: flex; align-items: center; gap: 16px; padding: 12px 24px;
29	    background: #12122a; border-bottom: 1px solid var(--card-border); flex-wrap: wrap;
30	  }
31	  .header-title { font-size: 1.4rem; font-weight: 700; color: #fff; }
32	  .version-badge {
33	    font-size: 0.7rem; background: var(--accent); color: #000; padding: 2px 8px;
34	    border-radius: 10px; font-weight: 600; vertical-align: middle;
35	  }
36	  .header-spacer { flex: 1; }
37	  .instance-toggle { display: flex; gap: 0; }
38	  .instance-btn {
39	    padding: 6px 18px; border: 1px solid var(--card-border); background: var(--card);
40	    color: var(--text-dim); cursor: pointer; font-size: 0.85rem; font-family: var(--font);
41	    transition: all 0.15s;
42	  }
43	  .instance-btn:first-child { border-radius: 6px 0 0 6px; }
44	  .instance-btn:last-child { border-radius: 0 6px 6px 0; }
45	  .instance-btn.active { background: var(--accent); color: #000; font-weight: 600; border-color: var(--accent); }
46	  .ctrl-btn {
47	    padding: 6px 16px; border: 1px solid var(--card-border); border-radius: 6px;
48	    background: var(--card); color: var(--text); cursor: pointer; font-size: 0.85rem;
49	    font-family: var(--font); transition: all 0.15s;
50	  }
51	  .ctrl-btn:hover { border-color: var(--accent); }
52	  .ctrl-btn.running { border-color: var(--red); color: var(--red); }
53	  .ctrl-btn.stopped { border-color: var(--green); color: var(--green); }
54	  .status-dot {
55	    width: 10px; height: 10px; border-radius: 50%; display: inline-block;
56	  }
57	  .status-dot.running { background: var(--green); box-shadow: 0 0 6px var(--green); }
58	  .status-dot.stopped { background: var(--red); }
59	  .status-dot.halted { background: #ff9800; box-shadow: 0 0 6px #ff9800; }
60	  .status-label { font-size: 0.85rem; color: var(--text-dim); margin-left: 4px; }
61	  .market-status {
62	    font-size: 0.75rem; padding: 3px 10px; border-radius: 10px;
63	    font-weight: 600; margin-left: 8px;
64	  }
65	  .market-status.open { background: rgba(76,175,80,0.2); color: var(--green); }
66	  .market-status.closed { background: rgba(239,83,80,0.2); color: var(--red); }
67	  /* Live mode warning */
68	  body.live-mode .header { border-bottom: 2px solid var(--red); }
69	  .live-warning { display: none; font-size: 0.7rem; background: var(--red); color: #fff; padding: 2px 8px; border-radius: 10px; font-weight: 700; margin-left: 6px; }
70	  body.live-mode .live-warning { display: inline-block; }
71	  .health-badge { font-size: 0.72rem; padding: 3px 10px; border-radius: 10px; font-weight: 600; }
72	  .health-badge.ok { background: rgba(76,175,80,0.2); color: var(--green); }
73	  .health-badge.warn { background: rgba(255,152,0,0.2); color: #ff9800; }
74	  .health-badge.bad { background: rgba(239,83,80,0.2); color: var(--red); }
75	  .header-meta { display: flex; align-items: center; gap: 12px; font-size: 0.75rem; color: var(--text-dim); }
76	  .next-cycle { font-family: var(--mono); }
77	  .last-updated { font-family: var(--mono); opacity: 0.7; }
78	  .gear-btn {
79	    background: none; border: none; color: var(--text-dim); cursor: pointer;
80	    font-size: 1.3rem; padding: 4px 8px; transition: color 0.15s;
81	  }
82	  .gear-btn:hover { color: var(--accent); }
83	
84	  /* Main layout */
85	  .main { max-width: 1400px; margin: 0 auto; padding: 20px 24px; }
86	
87	  /* Cards row */
88	  .cards { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 20px; }
89	  .card {
90	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
91	    padding: 18px 20px;
92	  }
93	  .card-label { font-size: 0.78rem; color: var(--text-dim); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
94	  .card-label[data-tip] { cursor: help; border-bottom: 1px dotted var(--text-dim); }
95	  .card-sub { font-size: 0.75rem; color: var(--text-dim); font-family: var(--mono); margin-top: 2px; }
96	  .card-sub.positive { color: var(--green); }
97	  .card-sub.negative { color: var(--red); }
98	  .card-value { font-size: 1.6rem; font-weight: 700; font-family: var(--mono); }
99	  /* Margin bar */
100	  .margin-bar-track { height: 6px; background: #1e1e40; border-radius: 3px; margin-top: 6px; overflow: hidden; }
101	  .margin-bar-fill { height: 100%; border-radius: 3px; transition: width 0.3s; }
102	  /* Tooltips */
103	  [data-tip] { position: relative; }
104	  [data-tip]:hover::after {
105	    content: attr(data-tip); position: absolute; bottom: 100%; left: 50%;
106	    transform: translateX(-50%); padding: 6px 10px; background: #222244;
107	    border: 1px solid var(--card-border); border-radius: 6px; font-size: 0.72rem;
108	    color: var(--text); white-space: normal; width: max-content; max-width: 240px;
109	    z-index: 100; pointer-events: none; font-weight: 400; text-transform: none;
110	    letter-spacing: normal; line-height: 1.4; margin-bottom: 4px;
111	  }
112	  .card-value.positive { color: var(--green); }
113	  .card-value.negative { color: var(--red); }
114	
115	  /* Panels */
116	  .panel {
117	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
118	    padding: 18px 20px; margin-bottom: 20px;
119	  }
120	  .panel-title { font-size: 1rem; font-weight: 600; margin-bottom: 12px; color: #fff; }
121	
122	  /* Tables */
123	  .table-wrap { overflow-x: auto; }
124	  table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
125	  th { text-align: left; color: var(--text-dim); font-weight: 500; padding: 8px 10px;
126	       border-bottom: 1px solid var(--card-border); white-space: nowrap; font-size: 0.75rem;
127	       text-transform: uppercase; letter-spacing: 0.5px; }
128	  td { padding: 7px 10px; border-bottom: 1px solid #1e1e40; white-space: nowrap; font-family: var(--mono); font-size: 0.8rem; }
129	  tr:hover td { background: rgba(79, 195, 247, 0.04); }
130	  .dir-buy { color: var(--green); font-weight: 600; }
131	  .dir-sell { color: var(--red); font-weight: 600; }
132	  .dir-hold { color: var(--hold); }
133	  .scrollable-table { max-height: 340px; overflow-y: auto; }
134	
135	  /* Chart */
136	  .chart-container { position: relative; height: 280px; }
137	
138	  /* Bot log */
139	  .log-entry {
140	    border: 1px solid var(--card-border); border-radius: 8px; margin-bottom: 8px;
141	    overflow: hidden;
142	  }
143	  .log-header {
144	    display: flex; justify-content: space-between; align-items: center;
145	    padding: 10px 14px; cursor: pointer; background: rgba(255,255,255,0.02);
146	    transition: background 0.15s;
147	  }
148	  .log-header:hover { background: rgba(79, 195, 247, 0.05); }
149	  .log-cycle { font-weight: 600; font-family: var(--mono); font-size: 0.85rem; }
150	  .log-time { font-size: 0.75rem; color: var(--text-dim); }
151	  .log-arrow { color: var(--text-dim); transition: transform 0.2s; font-size: 0.8rem; }
152	  .log-arrow.open { transform: rotate(90deg); }
153	  .log-body { padding: 0 14px 12px; display: none; font-size: 0.82rem; }
154	  .log-body.open { display: block; }
155	  .log-stat { display: inline-block; margin-right: 18px; margin-top: 4px; }
156	  .log-stat-label { color: var(--text-dim); font-size: 0.75rem; }
157	  .log-stat-value { font-family: var(--mono); font-weight: 600; }
158	
159	  /* Leaderboard hero */
160	  .leaderboard-hero { margin-bottom: 20px; }
161	  .leaderboard-hero .panel-title { font-size: 1.1rem; }
162	  .leaderboard-total {
163	    font-size: 0.78rem; color: var(--text-dim); font-weight: 400;
164	    margin-left: 12px; font-family: var(--mono);
165	  }
166	  .leaderboard-table { width: 100%; border-collapse: collapse; font-size: 0.85rem; }
167	  .leaderboard-table th {
168	    text-align: left; padding: 10px 12px; color: var(--text-dim); font-size: 0.72rem;
169	    text-transform: uppercase; letter-spacing: 0.5px;
170	    border-bottom: 2px solid var(--card-border); white-space: nowrap;
171	  }
172	  .leaderboard-table th.col-num { text-align: right; }
173	  .leaderboard-table th.col-rank { width: 36px; text-align: center; }
174	  .leaderboard-table th.col-status { width: 60px; text-align: center; }
175	  .leaderboard-table td { padding: 12px 12px; border-bottom: 1px solid rgba(42,42,94,0.3); }
176	  .leaderboard-table tr:last-child td { border-bottom: none; }
177	  .leaderboard-table tr:hover { background: rgba(79,195,247,0.04); }
178	  .leaderboard-table .rank {
179	    font-weight: 800; font-family: var(--mono); text-align: center;
180	    font-size: 1rem; width: 36px;
181	  }
182	  .leaderboard-table .rank-1 { color: #ffd700; }
183	  .leaderboard-table .rank-2 { color: #c0c0c0; }
184	  .leaderboard-table .rank-3 { color: #cd7f32; }
185	  .leaderboard-table .rank-4 { color: var(--text-dim); }
186	  .leaderboard-table .strategy-name {
187	    font-weight: 700; text-transform: capitalize; font-size: 0.95rem;
188	  }
189	  .leaderboard-table .num {
190	    text-align: right; font-family: var(--mono); font-weight: 500;
191	  }
192	  .leaderboard-table .strategy-btn {
193	    padding: 4px 14px; border: 1px solid var(--card-border); border-radius: 4px;
194	    background: transparent; color: var(--text-dim); cursor: pointer; font-size: 0.75rem;
195	    font-family: var(--font); transition: all 0.15s;
196	  }
197	  .leaderboard-table .strategy-btn:hover { border-color: var(--accent); color: var(--accent); }
198	  .leaderboard-table .strategy-btn.active { border-color: var(--green); color: var(--green); }
199	  .leaderboard-table .win-rate-bar {
200	    display: inline-block; width: 50px; height: 6px; background: rgba(255,255,255,0.08);
201	    border-radius: 3px; overflow: hidden; vertical-align: middle; margin-left: 6px;
202	  }
203	  .leaderboard-table .win-rate-fill {
204	    height: 100%; border-radius: 3px; transition: width 0.3s;
205	  }
206	
207	  /* Engine footer */
208	  .engine-footer {
209	    display: flex; flex-wrap: wrap; gap: 24px; align-items: center;
210	    padding: 14px 20px; background: var(--card); border: 1px solid var(--card-border);
211	    border-radius: 10px; margin-bottom: 20px; font-size: 0.82rem;
212	  }
213	  .engine-stat-label { color: var(--text-dim); font-size: 0.72rem; text-transform: uppercase; }
214	  .engine-stat-value { font-family: var(--mono); font-weight: 600; }
215	  .halted-warning { color: #ff9800; font-weight: 600; }
216	
217	  /* Settings modal */
218	  .modal-overlay {
219	    display: none; position: fixed; inset: 0; background: rgba(0,0,0,0.7);
220	    z-index: 1000; justify-content: center; align-items: center;
221	  }
222	  .modal-overlay.open { display: flex; }
223	  .modal {
224	    background: var(--card); border: 1px solid var(--card-border); border-radius: 12px;
225	    padding: 24px 28px; width: 460px; max-width: 95vw; max-height: 90vh; overflow-y: auto;
226	  }
227	  .modal-title { font-size: 1.1rem; font-weight: 700; color: #fff; margin-bottom: 18px; }
228	  .form-group { margin-bottom: 14px; }
229	  .form-label { display: block; font-size: 0.78rem; color: var(--text-dim); margin-bottom: 4px; text-transform: uppercase; letter-spacing: 0.3px; }
230	  .form-input {
231	    width: 100%; padding: 8px 12px; background: var(--bg); border: 1px solid var(--card-border);
232	    border-radius: 6px; color: var(--text); font-family: var(--mono); font-size: 0.85rem;
233	  }
234	  .form-input:focus { outline: none; border-color: var(--accent); }
235	  .modal-actions { display: flex; justify-content: flex-end; gap: 10px; margin-top: 20px; }
236	  .btn-save {
237	    padding: 8px 20px; background: var(--accent); color: #000; border: none;
238	    border-radius: 6px; cursor: pointer; font-weight: 600; font-family: var(--font); font-size: 0.85rem;
239	  }
240	  .btn-cancel {
241	    padding: 8px 20px; background: transparent; color: var(--text-dim); border: 1px solid var(--card-border);
242	    border-radius: 6px; cursor: pointer; font-family: var(--font); font-size: 0.85rem;
243	  }
244	  .btn-save:hover { filter: brightness(1.1); }
245	  .btn-cancel:hover { border-color: var(--text-dim); }
246	
247	  .no-data { color: var(--text-dim); font-style: italic; padding: 16px 0; font-size: 0.85rem; }
248	
249	  /* Bot Summary */
250	  .panel.summary-panel {
251	    border-left: 3px solid var(--accent);
252	    background: linear-gradient(135deg, var(--card) 0%, rgba(79,195,247,0.06) 100%);
253	  }
254	  .panel.summary-panel .summary-text {
255	    font-size: 0.88rem; line-height: 1.6; color: var(--text);
256	  }
257	  .summary-section { margin-bottom: 12px; }
258	  .summary-section:last-child { margin-bottom: 0; }
259	  .summary-label { font-size: 0.7rem; color: var(--text-dim); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
260	  .summary-trade-row { display: flex; justify-content: space-between; align-items: center; padding: 4px 0; border-bottom: 1px solid #1e1e40; font-size: 0.8rem; font-family: var(--mono); }
261	  .summary-trade-row:last-child { border-bottom: none; }
262	  .summary-stats { display: flex; gap: 16px; flex-wrap: wrap; margin-top: 4px; }
263	  .summary-stat { font-family: var(--mono); font-size: 0.82rem; }
264	  .summary-stat-label { font-size: 0.7rem; color: var(--text-dim); }
265	
266	  /* Collapsible panels */
267	  .panel.collapsible .panel-title {
268	    cursor: pointer; user-select: none; display: flex; align-items: center; gap: 8px;
269	  }
270	  .panel.collapsible .panel-title .collapse-arrow {
271	    display: inline-block; font-size: 0.7rem; color: var(--text-dim);
272	    transition: transform 0.2s; flex-shrink: 0;
273	  }
274	  .panel.collapsible .panel-body { display: none; }
275	  .panel.collapsible.open .panel-body { display: block; }
276	  .panel.collapsible.open .panel-title .collapse-arrow { transform: rotate(90deg); }
277	
278	  /* Alert banner */
279	  #alertBanner {
280	    position: fixed; top: 0; left: 0; right: 0; z-index: 2000;
281	    padding: 12px 24px; font-size: 0.9rem; font-weight: 600;
282	    text-align: center; transform: translateY(-100%);
283	    transition: transform 0.35s ease; font-family: var(--font);
284	  }
285	  #alertBanner.visible { transform: translateY(0); }
286	  #alertBanner.trade { background: var(--green); color: #000; }
287	  #alertBanner.halted { background: #ff9800; color: #000; }
288	
289	  /* Open positions panel */
290	  .positions-grid { display: flex; flex-wrap: wrap; gap: 12px; }
291	  .position-card {
292	    background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px;
293	    padding: 12px 16px; min-width: 240px; flex: 1;
294	  }
295	  .position-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px; }
296	  .position-inst { font-family: var(--mono); font-weight: 600; font-size: 0.9rem; }
297	  .position-detail { font-size: 0.78rem; color: var(--text-dim); line-height: 1.7; }
298	  .position-detail span { font-family: var(--mono); color: var(--text); }
299	  .sl-tp-gauge { height: 6px; background: #1e1e40; border-radius: 3px; margin-top: 6px; position: relative; overflow: visible; }
300	  .sl-tp-gauge .price-marker { position: absolute; top: -3px; width: 4px; height: 12px; border-radius: 2px; }
301	  .sl-tp-gauge .sl-zone { position: absolute; left: 0; height: 100%; background: rgba(239,83,80,0.3); border-radius: 3px 0 0 3px; }
302	  .sl-tp-gauge .tp-zone { position: absolute; right: 0; height: 100%; background: rgba(76,175,80,0.3); border-radius: 0 3px 3px 0; }
303	
304	  /* Risk limits */
305	  .risk-limits { display: flex; flex-wrap: wrap; gap: 16px; }
306	  .risk-item { flex: 1; min-width: 160px; }
307	  .risk-label { font-size: 0.72rem; color: var(--text-dim); text-transform: uppercase; margin-bottom: 3px; }
308	  .risk-bar-track { height: 8px; background: #1e1e40; border-radius: 4px; overflow: hidden; }
309	  .risk-bar-fill { height: 100%; border-radius: 4px; transition: width 0.3s; }
310	  .risk-value { font-size: 0.72rem; font-family: var(--mono); margin-top: 2px; }
311	
312	  /* Calendar */
313	  .calendar-list { display: flex; flex-direction: column; gap: 6px; }
314	  .calendar-event { display: flex; align-items: center; gap: 10px; padding: 8px 12px; background: var(--bg); border: 1px solid var(--card-border); border-radius: 6px; font-size: 0.82rem; }
315	  .impact-badge { font-size: 0.68rem; font-weight: 700; padding: 2px 8px; border-radius: 10px; text-transform: uppercase; flex-shrink: 0; }
316	  .impact-high { background: rgba(239,83,80,0.2); color: var(--red); }
317	  .impact-medium { background: rgba(255,152,0,0.2); color: #ff9800; }
318	  .impact-low { background: rgba(136,136,170,0.2); color: var(--text-dim); }
319	  .calendar-time { font-family: var(--mono); font-size: 0.75rem; color: var(--text-dim); min-width: 70px; flex-shrink: 0; }
320	  .calendar-currency { font-family: var(--mono); font-weight: 600; min-width: 36px; flex-shrink: 0; }
321	
322	  /* Connection lost banner */
323	  #connBanner {
324	    display: none; padding: 8px 24px; text-align: center; font-size: 0.82rem;
325	    font-weight: 600; background: rgba(255,152,0,0.15); color: #ff9800;
326	    border-bottom: 1px solid rgba(255,152,0,0.3);
327	  }
328	  #connBanner.visible { display: block; }
329	
330	  /* Scoring mode badge */
331	  .mode-badge { font-size: 0.7rem; padding: 2px 8px; border-radius: 10px; font-weight: 600; margin-left: 8px; }
332	  .mode-badge.rules { background: rgba(136,136,170,0.2); color: var(--text-dim); }
333	  .mode-badge.ml { background: rgba(79,195,247,0.2); color: var(--accent); }
334	
335	  /* Time range buttons */
336	  .time-range-btns { display: flex; gap: 4px; margin-bottom: 10px; }
337	  .time-range-btn {
338	    padding: 3px 10px; font-size: 0.72rem; border: 1px solid var(--card-border);
339	    border-radius: 4px; background: var(--card); color: var(--text-dim);
340	    cursor: pointer; font-family: var(--font); transition: all 0.15s;
341	  }
342	  .time-range-btn.active { background: var(--accent); color: #000; border-color: var(--accent); font-weight: 600; }
343	
344	  /* LLM Advisor */
345	  .llm-regime { display: flex; gap: 16px; flex-wrap: wrap; margin-bottom: 12px; }
346	  .llm-regime-item { background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px; padding: 8px 14px; }
347	  .llm-regime-label { font-size: 0.72rem; color: var(--text-dim); text-transform: uppercase; }
348	  .llm-regime-value { font-family: var(--mono); font-size: 0.9rem; font-weight: 600; }
349	  .llm-decisions { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 10px; }
350	  .llm-decision { background: var(--bg); border: 1px solid var(--card-border); border-radius: 6px; padding: 6px 12px; font-size: 0.8rem; }
351	  .llm-decision.approved { border-color: var(--green); }
352	  .llm-decision.vetoed { border-color: var(--red); }
353	  .llm-lessons { font-size: 0.82rem; color: var(--text-dim); line-height: 1.6; border-left: 3px solid var(--accent); padding-left: 12px; margin-top: 10px; }
354	
355	  /* Sparkline price charts */
356	  .sparkline-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 12px; }
357	  .sparkline-card {
358	    background: var(--bg); border: 1px solid var(--card-border); border-radius: 8px;
359	    padding: 10px 14px; position: relative;
360	  }
361	  .sparkline-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 4px; }
362	  .sparkline-inst { font-family: var(--mono); font-weight: 600; font-size: 0.85rem; }
363	  .sparkline-price { font-family: var(--mono); font-size: 0.8rem; }
