1652	    warnings.push('\u26A0 Model accuracy is low (' + (eng.model_accuracy * 100).toFixed(1) + '%).');
1653	  }
1654	  // Check risk limits
1655	  if (eng && eng.peak_equity > 0) {
1656	    const dailyPct = eng.daily_loss_limit > 0 ? Math.abs(eng.daily_pnl) / (eng.daily_loss_limit * eng.peak_equity) * 100 : 0;
1657	    if (dailyPct >= 100) warnings.push('\u26A0 Daily loss limit reached!');
1658	    else if (dailyPct >= 75) warnings.push('\u26A0 Daily loss at ' + dailyPct.toFixed(0) + '% of limit.');
1659	    const ddPct = eng.max_drawdown > 0 ? (eng.current_drawdown / eng.max_drawdown) * 100 : 0;
1660	    if (ddPct >= 80) warnings.push('\u26A0 Drawdown at ' + ddPct.toFixed(0) + '% of limit.');
1661	  }
1662	  return warnings;
1663	}
