1966	function drawSparkline(canvas, values) {
1967	  const ctx = canvas.getContext('2d');
1968	  const dpr = window.devicePixelRatio || 1;
1969	  const w = canvas.clientWidth;
1970	  const h = canvas.clientHeight;
1971	  canvas.width = w * dpr;
1972	  canvas.height = h * dpr;
1973	  ctx.scale(dpr, dpr);
1974	
1975	  const min = Math.min(...values);
1976	  const max = Math.max(...values);
1977	  const range = max - min || 1;
1978	  const stepX = w / (values.length - 1);
1979	
1980	  // Determine color based on overall direction
1981	  const up = values[values.length - 1] >= values[0];
1982	  const lineColor = up ? '#4caf50' : '#ef5350';
1983	  const fillColor = up ? 'rgba(76,175,80,0.1)' : 'rgba(239,83,80,0.1)';
1984	
1985	  // Fill area
1986	  ctx.beginPath();
1987	  ctx.moveTo(0, h);
1988	  values.forEach((v, i) => {
1989	    const x = i * stepX;
1990	    const y = h - ((v - min) / range) * (h - 4) - 2;
1991	    if (i === 0) ctx.lineTo(x, y);
1992	    else ctx.lineTo(x, y);
1993	  });
1994	  ctx.lineTo(w, h);
1995	  ctx.closePath();
1996	  ctx.fillStyle = fillColor;
1997	  ctx.fill();
1998	
1999	  // Line
2000	  ctx.beginPath();
2001	  values.forEach((v, i) => {
2002	    const x = i * stepX;
2003	    const y = h - ((v - min) / range) * (h - 4) - 2;
2004	    if (i === 0) ctx.moveTo(x, y);
2005	    else ctx.lineTo(x, y);
2006	  });
2007	  ctx.strokeStyle = lineColor;
2008	  ctx.lineWidth = 1.5;
2009	  ctx.stroke();
2010	
2011	  // Current price dot
2012	  const lastX = (values.length - 1) * stepX;
2013	  const lastY = h - ((values[values.length - 1] - min) / range) * (h - 4) - 2;
2014	  ctx.beginPath();
2015	  ctx.arc(lastX, lastY, 3, 0, Math.PI * 2);
2016	  ctx.fillStyle = lineColor;
2017	  ctx.fill();
2018	}
